from dataclasses import dataclass

@dataclass
class Score:
    value: float
    def validate(self):
        if not (0 <= self.value <= 1):
            raise ValueError("score fuera de [0,1]")
        return self

print(Score(0.5).validate())

from typing import Protocol

class EntityStore(Protocol):
    def get(self, id: str): ...
    def save(self, entity) -> None: ...

class InMemoryStore:
    def __init__(self):
        self._d = {}
    def get(self, id: str):
        return self._d.get(id)
    def save(self, entity) -> None:
        self._d[entity["id"]] = entity

s: EntityStore = InMemoryStore()
s.save({"id": "C1"})
print(s.get("C1"))

class FakeStore:
    def get(self, id: str):
        return {"id": id, "fake": True}
    def save(self, entity) -> None:
        pass

print(FakeStore().get("C9"))

