def to_dict(obj):
    if hasattr(obj, "__dict__"):
        return {k: to_dict(v) if hasattr(v, "__dict__") else v for k, v in obj.__dict__.items()}
    return obj

class P:
    def __init__(self, n):
        self.n = n
print(to_dict(P("x")))

from dataclasses import dataclass, asdict

@dataclass
